struct MaterializationGuard<'a> {
    active: &'a RefCell<HashSet<usize>>,
    key: usize,
}

impl Drop for MaterializationGuard<'_> {
    fn drop(&mut self) {
        self.active.borrow_mut().remove(&self.key);
    }
}

