                        self.instructions.push(0x1a);
                        self.emit_numeric_expression(property)?;
                        self.instructions.push(0x1a);
                        let temp_local = self.allocate_temp_local();
                        self.emit_numeric_expression(value)?;
                        self.push_local_set(temp_local);
